import { ref, onMounted, onUnmounted, watch, type Ref } from 'vue'
import { hasIntersectionObserver } from '@/lib/env'

export interface UseInfiniteScrollOptions {
    /** 触发距离阈值 (px) */
    distance?: number
    /** 防抖延迟 (ms) */
    delay?: number
    /** 是否禁用 */
    disabled?: boolean
    /** 是否立即检查 */
    immediate?: boolean
    /** 加载回调 */
    onLoad: () => void
}

const DEFAULT_DISTANCE = 100
const DEFAULT_DELAY = 200
type ObserverSetupResult = 'observed' | 'unsupported' | 'missing-target'

export function useInfiniteScroll(
    targetRef: Ref<HTMLElement | null>,
    options: UseInfiniteScrollOptions
) {
    // 使用 getter 读取最新值，避免在 setup 时静态捕获导致后续变更不生效
    const getDistance = (): number => options.distance ?? DEFAULT_DISTANCE
    const getDelay = (): number => options.delay ?? DEFAULT_DELAY
    const getDisabled = (): boolean => options.disabled ?? false

    const isLoading = ref(false)
    const observer = ref<IntersectionObserver | null>(null)
    const loadTimer = ref<ReturnType<typeof setTimeout> | null>(null)

    function shouldLoad(): boolean {
        if (getDisabled()) return false
        if (isLoading.value) return false
        return true
    }

    function triggerLoad() {
        if (!shouldLoad()) return

        if (loadTimer.value) {
            clearTimeout(loadTimer.value)
        }

        loadTimer.value = setTimeout(() => {
            isLoading.value = true
            options.onLoad()
        }, getDelay())
    }

    function setupObserver(): ObserverSetupResult {
        if (!targetRef.value) return 'missing-target'
        if (!hasIntersectionObserver) return 'unsupported'

        observer.value = new IntersectionObserver(
            (entries) => {
                const entry = entries[0]
                if (entry.isIntersecting) {
                    triggerLoad()
                }
            },
            {
                root: null,
                rootMargin: `${getDistance()}px`,
                threshold: 0,
            }
        )

        observer.value.observe(targetRef.value)
        return 'observed'
    }

    function cleanupObserver() {
        if (observer.value) {
            observer.value.disconnect()
            observer.value = null
        }
    }

    function resetLoading() {
        isLoading.value = false
    }

    onMounted(() => {
        if (!getDisabled()) {
            const observerResult = setupObserver()

            if ((options.immediate ?? true) || observerResult === 'unsupported') {
                triggerLoad()
            }
        }
    })

    // 监听 distance 变化，重新创建 observer 以应用新的 rootMargin
    watch(
        () => options.distance,
        () => {
            if (observer.value) {
                cleanupObserver()
                if (!getDisabled()) {
                    setupObserver()
                }
            }
        }
    )

    // 监听 disabled 变化，动态启停 observer
    watch(
        () => options.disabled,
        (newDisabled) => {
            if (newDisabled) {
                cleanupObserver()
            } else if (!observer.value && targetRef.value) {
                const observerResult = setupObserver()
                if (observerResult === 'unsupported') {
                    triggerLoad()
                }
            }
        }
    )

    onUnmounted(() => {
        cleanupObserver()
        if (loadTimer.value) {
            clearTimeout(loadTimer.value)
        }
    })

    return {
        isLoading,
        resetLoading,
    }
}

import { ref, onMounted, onUnmounted, type Ref } from 'vue'
import { isClient } from '@/lib/env'

export function useReducedMotion(): Ref<boolean> {
    const prefersReduced = ref(false)
    let mediaQuery: MediaQueryList | null = null

    const onChange = (e: MediaQueryListEvent) => {
        prefersReduced.value = e.matches
    }

    onMounted(() => {
        if (isClient) {
            mediaQuery = window.matchMedia('(prefers-reduced-motion: reduce)')
            prefersReduced.value = mediaQuery.matches
            mediaQuery.addEventListener('change', onChange)
        }
    })

    onUnmounted(() => {
        mediaQuery?.removeEventListener('change', onChange)
    })

    return prefersReduced
}

/**
 * Environment detection utilities for SSR compatibility.
 * Use these instead of scattered `typeof document/window` checks.
 */

/** Whether the code is running in a browser environment (not SSR). */
export const isClient = typeof window !== 'undefined'

/** Whether `document` is available. */
export const hasDocument = typeof document !== 'undefined'

/** Whether `localStorage` is available (may be blocked in Safari private mode). */
export const hasLocalStorage = typeof localStorage !== 'undefined'

/** Whether `document.body` is available for imperative mounting. */
export function canUseDocumentBody(): boolean {
    return hasDocument && document.body !== null
}

/** Whether IntersectionObserver is available. */
export const hasIntersectionObserver = isClient && typeof window.IntersectionObserver !== 'undefined'

type AudioContextConstructor = typeof AudioContext

/** Get the available AudioContext constructor, including Safari's prefixed API. */
export function getAudioContextCtor(): AudioContextConstructor | null {
    if (!isClient) return null
    return window.AudioContext
        ?? (window as Window & typeof globalThis & { webkitAudioContext?: AudioContextConstructor }).webkitAudioContext
        ?? null
}

/**
 * Safely get a value from localStorage.
 * Returns `null` if localStorage is unavailable or the key doesn't exist.
 */
export function safeGetStorageItem(key: string): string | null {
    try {
        if (!hasLocalStorage) return null
        return localStorage.getItem(key)
    } catch {
        return null
    }
}

/**
 * Safely set a value in localStorage.
 * Silently fails if localStorage is unavailable (e.g. Safari private mode, storage full).
 */
export function safeSetStorageItem(key: string, value: string): void {
    try {
        if (!hasLocalStorage) return
        localStorage.setItem(key, value)
    } catch {
        // Storage full or blocked (e.g. Safari private mode)
    }
}
